  "schema": {
    "fields": [
      {
        "name": "auction_id",
        "type": "integer",
        "title": "Auction ID",
        "description": "Unique auction identifier. Stable across all products auctioned in the same market window.",
        "comment": "Primary-key component; pairs with product_code to uniquely reference a cleared bid.",
        "unit": null
      },
      {
        "name": "product_code",
        "type": "string",
        "title": "Product Code",
        "description": "Product mnemonic for the balancing service (e.g. DCL, DCH, FFR).",
        "comment": "Primary-key component; controlled vocabulary maintained by the market operator.",
        "unit": null
      },
      {
        "name": "delivery_start",
        "type": "datetime",
        "title": "Delivery Start (UTC)",
        "description": "First instant of the delivery window. Stored as UTC; clients render local time.",
        "comment": "Always persisted as UTC \u2014 do not assume the caller's timezone.",
        "unit": null
      },
      {
        "name": "duration_minutes",
        "type": "integer",
        "title": "Delivery Duration",
        "description": "Length of the delivery window.",
        "comment": "Add to delivery_start to derive the delivery end instant.",
        "unit": "minutes",
        "info": {
          "unit": "minutes"
        }
      },
      {
        "name": "clearing_price_gbp_per_mwh",
        "type": "number",
        "title": "Clearing Price",
        "description": "Pay-as-cleared price for the auction. Negative values are possible during oversupply.",
        "comment": "Pay-as-cleared: every accepted bid settles at this price, not its own offer.",
        "unit": "GBP/MWh",
        "info": {
          "unit": "GBP/MWh"
        }
      },
      {
        "name": "volume_mwh",
        "type": "number",
        "title": "Cleared Volume",
        "description": "Total volume cleared in this auction.",
        "comment": "Sum across accepted bids for the (auction_id, product_code) pair.",
        "unit": "MWh",
        "info": {
          "unit": "MWh"
        }
      },
      {
        "name": "accepted",
        "type": "boolean",
        "title": "Accepted",
        "description": "Whether the bid cleared (true) or was rejected (false).",
        "comment": "Rejected rows are retained for audit; filter accepted=true for settlement.",
        "unit": null
      },
      {
        "name": "bidder_metadata",
        "type": "object",
        "title": "Bidder Metadata",
        "description": "Free-form provider-specific metadata captured at submission time.",
        "comment": "Schema not enforced; kept opaque for downstream analytics.",
        "unit": null
      }
    ],
    "primaryKey": [
      "auction_id",
      "product_code"
    ]
  },
